/** Shows fill price and slippage vs limit/requested price */
function FillQuality({ order }) {
  const fillPrice = order?.avg_fill ?? order?.price;
  const requestedPrice = order?.limit_price ?? order?.requested_price;
  if (fillPrice == null) return <span className={s.priceText}>{fillPrice != null ? `$${Number(fillPrice).toFixed(2)}` : '--'}</span>;

  const slip = requestedPrice != null ? fillPrice - requestedPrice : null;
  const slipPct = requestedPrice != null && requestedPrice !== 0 ? (slip / requestedPrice) * 100 : null;
  const sideUpper = (order?.side || '').toUpperCase();
  let slipColor = C.textSecondary;
  if (slip != null) {
    const isBuy = sideUpper === 'BUY' || sideUpper === 'BOT' || sideUpper === 'LONG';
    slipColor = (isBuy ? slip > 0 : slip < 0) ? C.red : C.green;
  }

  return (
    <div className={s.fillQualityWrap}>
      <span className={s.priceText}>${Number(fillPrice).toFixed(2)}</span>
      {slip != null && (
        <span className={s.slippageText} style={{ color: slipColor }}>
          {slip >= 0 ? '+' : ''}{slip.toFixed(3)}
          {slipPct != null ? ` (${slipPct >= 0 ? '+' : ''}${slipPct.toFixed(2)}%)` : ''}
        </span>
      )}
    </div>
  );
}

/** Mini timeline of order lifecycle events */
function OrderTimeline({ order }) {
  const steps = [];

  const submitTs = order?.timestamp ?? order?.ts ?? order?.submit_time;
  const ackTs = order?.ack_time ?? order?.acknowledged_at;
  const fillTs = order?.fill_time ?? order?.filled_at;
  const rejectTs = order?.reject_time ?? order?.rejected_at;
  const cancelTs = order?.cancel_time ?? order?.cancelled_at;

  if (submitTs) steps.push({ label: 'Submitted', ts: submitTs, color: C.blue });
  if (ackTs)    steps.push({ label: 'Acknowledged', ts: ackTs, color: C.amber });
  if (fillTs)   steps.push({ label: 'Filled', ts: fillTs, color: C.green });
  if (rejectTs) steps.push({ label: 'Rejected', ts: rejectTs, color: C.red });
  if (cancelTs) steps.push({ label: 'Cancelled', ts: cancelTs, color: C.textSecondary });

  if (steps.length === 1) {
    const st = (order?.status || '').toLowerCase();
    if (st === 'filled' || st === 'partial') {
      steps.push({ label: 'Filled', ts: null, color: C.green });
    } else if (st === 'rejected' || st === 'failed') {
      steps.push({ label: 'Rejected', ts: null, color: C.red });
    } else if (st === 'cancelled' || st === 'canceled') {
      steps.push({ label: 'Cancelled', ts: null, color: C.textSecondary });
    } else if (st === 'pending' || st === 'open' || st === 'new') {
      steps.push({ label: 'Pending', ts: null, color: C.amber });
    }
  }

  if (steps.length === 0) return <span className={s.timelineEmpty}>--</span>;

  const fmt = (ts) => ts
    ? new Date(ts).toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', second: '2-digit', hour12: false })
    : null;

  return (
    <div className={s.timeline}>
      {steps.map((step, i) => (
        <div key={i} className={s.timelineStep}>
          <span className={s.timelineDot} style={{ background: step.color }} />
          {i < steps.length - 1 && <span className={s.timelineConnector} />}
          <div className={s.timelineLabel}>
            <span style={{ color: step.color }}>{step.label}</span>
            {step.ts && <span className={s.timelineTs}>{fmt(step.ts)}</span>}
          </div>
        </div>
      ))}
    </div>
  );
}

/** Returns start-of-day, start-of-week, start-of-month timestamps */
function getDateRangeStart(rangeKey) {
  const now = new Date();
  if (rangeKey === 'today') {
    return new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime();
  }
  if (rangeKey === 'week') {
    const day = now.getDay();
    const diff = now.getDate() - day + (day === 0 ? -6 : 1);
    return new Date(now.getFullYear(), now.getMonth(), diff).getTime();
  }
  if (rangeKey === 'month') {
    return new Date(now.getFullYear(), now.getMonth(), 1).getTime();
  }
  return null;
}

/** Sum realized P&L from today's filled orders */
function computeTodayPnl(orders) {
  const todayStart = getDateRangeStart('today');
  let total = 0;
  let count = 0;
  for (const o of orders) {
    const st = (o?.status || '').toLowerCase();
    if (st !== 'filled' && st !== 'partial') continue;
    const ts = o?.timestamp ?? o?.ts ?? o?.fill_time;
    if (!ts) continue;
    const t = new Date(ts).getTime();
    if (isNaN(t) || t < todayStart) continue;
    if (o?.realized_pnl != null) {
      total += Number(o.realized_pnl);
      count++;
    } else if (o?.price != null && o?.qty != null) {
      const sideUpper = (o?.side || '').toUpperCase();
      const isSell = sideUpper === 'SELL' || sideUpper === 'SLD' || sideUpper === 'SHORT';
      if (isSell) {
        const avgCost = o?.avg_cost ?? o?.entry_price ?? null;
        if (avgCost != null) {
          total += (Number(o.price) - Number(avgCost)) * Math.abs(Number(o.qty));
          count++;
        }
      }
    }
  }
  return { total, count };
}

