/** Hook to fetch blotter data from multiple endpoints */
function useBlotter() {
  const [blotter, setBlotter] = useState([]);
  const [execQuality, setExecQuality] = useState(null);
  const [loading, setLoading] = useState(true);
  const prevIdsRef = useRef(new Set());

  const fetchBlotter = useCallback(async () => {
    try {
      // Fetch from multiple sources in parallel
      const [blotterData, ordersData, eqData] = await Promise.all([
        api('/positions/orders/blotter', { silent: true }).catch(() => null),
        api('/orders', { silent: true }).catch(() => null),
        api('/v2/console/execution-quality', { silent: true }).catch(() => null),
      ]);

      // Merge blotter and orders data
      let entries = [];
      if (blotterData) {
        const raw = Array.isArray(blotterData) ? blotterData : (blotterData?.blotter ?? blotterData?.orders ?? []);
        entries = Array.isArray(raw) ? raw : [];
      }

      // If /api/orders returned data, merge any orders not in blotter
      if (ordersData) {
        const ordRaw = Array.isArray(ordersData) ? ordersData : (ordersData?.orders ?? []);
        if (Array.isArray(ordRaw) && ordRaw.length > 0) {
          const existingIds = new Set(entries.map(e => e.id || `${e.symbol}-${e.timestamp}`));
          for (const o of ordRaw) {
            const oid = o.id || `${o.symbol}-${o.timestamp}`;
            if (!existingIds.has(oid)) {
              entries.push(o);
            }
          }
        }
      }

      // Enrich with execution quality data
      if (eqData) {
        setExecQuality(eqData);
        const eqLookup = {};
        const eqOrders = eqData?.orders || eqData?.executions || [];
        if (Array.isArray(eqOrders)) {
          for (const eq of eqOrders) {
            if (eq.order_id || eq.id) eqLookup[eq.order_id || eq.id] = eq;
            if (eq.symbol && eq.timestamp) eqLookup[`${eq.symbol}-${eq.timestamp}`] = eq;
          }
        }
        entries = entries.map(e => {
          const key = e.id || `${e.symbol}-${e.timestamp}`;
          const eq = eqLookup[key] || eqLookup[e.id];
          if (eq) {
            return {
              ...e,
              slippage: e.slippage ?? eq.slippage ?? null,
              slippage_pct: e.slippage_pct ?? eq.slippage_pct ?? null,
              fill_latency_ms: e.fill_latency_ms ?? eq.fill_latency_ms ?? eq.latency_ms ?? null,
              strategy: e.strategy ?? eq.strategy ?? eq.strategy_name ?? null,
              avg_fill: e.avg_fill ?? eq.avg_fill ?? eq.fill_price ?? null,
              limit_price: e.limit_price ?? eq.limit_price ?? eq.requested_price ?? null,
            };
          }
          return e;
        });
      }

      setBlotter(entries);
      return entries;
    } catch {
      return [];
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchBlotter();
    const id = setInterval(fetchBlotter, 30000);
    return () => clearInterval(id);
  }, [fetchBlotter]);

  return { blotter, execQuality, loading, fetchBlotter };
}

/** Fill notification toast system */
function useFillToasts(blotter) {
  const [toasts, setToasts] = useState([]);
  const prevFillIdsRef = useRef(new Set());
  const isInitRef = useRef(true);

  useEffect(() => {
    const currentFillIds = new Set();
    const newFills = [];

    for (const order of blotter) {
      const st = (order?.status || '').toLowerCase();
      if (st !== 'filled' && st !== 'partial') continue;
      const id = order?.id || `${order?.symbol}-${order?.timestamp}`;
      currentFillIds.add(id);
      if (!isInitRef.current && !prevFillIdsRef.current.has(id)) {
        newFills.push(order);
      }
    }

    prevFillIdsRef.current = currentFillIds;
    isInitRef.current = false;

    if (newFills.length > 0) {
      const newToasts = newFills.map((order, i) => ({
        id: `${Date.now()}-${i}`,
        symbol: order.symbol,
        side: order.side,
        qty: order.qty,
        price: order.price || order.avg_fill,
        status: order.status,
      }));
      setToasts(prev => [...prev, ...newToasts]);
    }
  }, [blotter]);

  // Auto-remove toasts after 5s
  useEffect(() => {
    if (toasts.length === 0) return;
    const timer = setTimeout(() => {
      setToasts(prev => prev.slice(1));
    }, 5000);
    return () => clearTimeout(timer);
  }, [toasts]);

  const dismissToast = useCallback((id) => {
    setToasts(prev => prev.filter(t => t.id !== id));
  }, []);

  return { toasts, dismissToast };
}

// ─── Bracket Order Builder ────────────────────────────────────────────────────
function BracketOrderBuilder({ onClose }) {
  const [symbol, setSymbol] = useState('');
  const [side, setSide] = useState('BUY');
  const [orderType, setOrderType] = useState('LIMIT');
  const [qty, setQty] = useState('');
  const [entryPrice, setEntryPrice] = useState('');
  const [stopLoss, setStopLoss] = useState('');
  const [takeProfit, setTakeProfit] = useState('');
  const [submitting, setSubmitting] = useState(false);
  const [previewOpen, setPreviewOpen] = useState(false);
  const [result, setResult] = useState(null);

  const isBuy = side === 'BUY';
  const entryNum = parseFloat(entryPrice) || 0;
  const qtyNum = parseInt(qty) || 0;
  const slNum = parseFloat(stopLoss) || 0;
  const tpNum = parseFloat(takeProfit) || 0;

  // Estimated impact
  const estCost = entryNum * qtyNum;
  const estCommission = Math.max(1.0, qtyNum * 0.005); // IBKR estimate
  const riskPerShare = slNum > 0 ? Math.abs(entryNum - slNum) : 0;
  const rewardPerShare = tpNum > 0 ? Math.abs(tpNum - entryNum) : 0;
  const riskRewardRatio = riskPerShare > 0 && rewardPerShare > 0 ? (rewardPerShare / riskPerShare).toFixed(2) : '--';
  const totalRisk = riskPerShare * qtyNum;

  const handleSubmit = async () => {
    if (!symbol || !qty || !entryPrice) return;
    setSubmitting(true);
    try {
      const body = {
        symbol: symbol.toUpperCase(),
        side,
        order_type: orderType,
        qty: qtyNum,
        price: entryNum,
      };
      if (slNum > 0) body.stop_loss = slNum;
      if (tpNum > 0) body.take_profit = tpNum;

      await api('/positions/orders/submit', {
        method: 'POST',
        body: JSON.stringify(body),
        silent: true,
      });
      setResult({ ok: true, msg: `${side} ${qtyNum} ${symbol.toUpperCase()} submitted` });
      setTimeout(() => { setResult(null); onClose?.(); }, 2500);
    } catch (e) {
      setResult({ ok: false, msg: `Order failed: ${e?.message || 'Unknown error'}` });
      setTimeout(() => setResult(null), 3500);
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className={s.bracketBuilder}>
      <div className={s.bracketHeader}>
        <h3 className={s.bracketTitle}>Bracket Order</h3>
        <button className={s.bracketCloseBtn} onClick={onClose}>X</button>
      </div>

      {/* Symbol + Side */}
      <div className={s.bracketRow}>
        <div className={s.bracketField}>
          <label className={s.bracketLabel}>Symbol</label>
          <input
            type="text"
            className={s.bracketInput}
            value={symbol}
            onChange={(e) => setSymbol(e.target.value.toUpperCase())}
            placeholder="AAPL"
          />
        </div>
        <div className={s.bracketField}>
          <label className={s.bracketLabel}>Side</label>
          <div className={s.sideToggle}>
            <button
              className={isBuy ? s.sideToggleBuyActive : s.sideToggleBuy}
              onClick={() => setSide('BUY')}
            >
              BUY
            </button>
            <button
              className={!isBuy ? s.sideToggleSellActive : s.sideToggleSell}
              onClick={() => setSide('SELL')}
            >
              SELL
            </button>
          </div>
        </div>
      </div>

      {/* Type + Qty */}
      <div className={s.bracketRow}>
        <div className={s.bracketField}>
          <label className={s.bracketLabel}>Type</label>
          <select
            className={s.bracketSelect}
            value={orderType}
            onChange={(e) => setOrderType(e.target.value)}
          >
            <option value="LIMIT">Limit</option>
            <option value="MARKET">Market</option>
            <option value="STOP">Stop</option>
          </select>
        </div>
        <div className={s.bracketField}>
          <label className={s.bracketLabel}>Quantity</label>
          <input
            type="number"
            className={s.bracketInput}
            value={qty}
            onChange={(e) => setQty(e.target.value)}
            placeholder="100"
            min="1"
          />
        </div>
      </div>

      {/* Entry / SL / TP */}
      <div className={s.bracketTriple}>
        <div className={s.bracketField}>
          <label className={s.bracketLabel}>Entry Price</label>
          <input
            type="number"
            className={s.bracketInput}
            value={entryPrice}
            onChange={(e) => setEntryPrice(e.target.value)}
            placeholder="150.00"
            step="0.01"
          />
        </div>
        <div className={s.bracketField}>
          <label className={s.bracketLabel}>Stop Loss</label>
          <input
            type="number"
            className={[s.bracketInput, s.bracketInputSL].join(' ')}
            value={stopLoss}
            onChange={(e) => setStopLoss(e.target.value)}
            placeholder="145.00"
            step="0.01"
          />
        </div>
        <div className={s.bracketField}>
          <label className={s.bracketLabel}>Take Profit</label>
          <input
            type="number"
            className={[s.bracketInput, s.bracketInputTP].join(' ')}
            value={takeProfit}
            onChange={(e) => setTakeProfit(e.target.value)}
            placeholder="160.00"
            step="0.01"
          />
        </div>
      </div>

      {/* Order Preview */}
      {symbol && qty && entryPrice && (
        <div className={s.orderPreview}>
          <div className={s.previewHeader} onClick={() => setPreviewOpen(!previewOpen)}>
            <span className={s.previewTitle}>Order Preview</span>
            <span className={s.previewChevron}>{previewOpen ? '\u25BC' : '\u25B6'}</span>
          </div>
          {previewOpen && (
            <motion.div
              initial={{ height: 0, opacity: 0 }}
              animate={{ height: 'auto', opacity: 1 }}
              transition={{ duration: 0.15 }}
              className={s.previewBody}
            >
              <div className={s.previewRow}>
                <span className={s.previewLabel}>Est. Fill Price</span>
                <span className={s.previewValue}>${entryNum.toFixed(2)}</span>
              </div>
              <div className={s.previewRow}>
                <span className={s.previewLabel}>Total Cost</span>
                <span className={s.previewValue}>${estCost.toFixed(2)}</span>
              </div>
              <div className={s.previewRow}>
                <span className={s.previewLabel}>Est. Commission</span>
                <span className={s.previewValue}>${estCommission.toFixed(2)}</span>
              </div>
              {slNum > 0 && (
                <div className={s.previewRow}>
                  <span className={s.previewLabel}>Risk/Share</span>
                  <span className={s.previewValue} style={{ color: '#EF4444' }}>
                    ${riskPerShare.toFixed(2)} ({totalRisk > 0 ? `$${totalRisk.toFixed(0)} total` : '--'})
                  </span>
                </div>
              )}
              {riskRewardRatio !== '--' && (
                <div className={s.previewRow}>
                  <span className={s.previewLabel}>Risk/Reward</span>
                  <span className={s.previewValue} style={{
                    color: parseFloat(riskRewardRatio) >= 2 ? '#22C55E' : parseFloat(riskRewardRatio) >= 1 ? '#F59E0B' : '#EF4444'
                  }}>
                    1:{riskRewardRatio}
                  </span>
                </div>
              )}
            </motion.div>
          )}
        </div>
      )}

      {/* Submit */}
      <button
        className={s.bracketSubmit}
        disabled={!symbol || !qty || !entryPrice || submitting}
        onClick={handleSubmit}
      >
        {submitting ? 'Submitting...' : `Submit ${side} Order`}
      </button>

      {/* Result toast */}
      {result && (
        <div className={result.ok ? s.bracketResultOk : s.bracketResultErr}>
          {result.msg}
        </div>
      )}
    </div>
  );
}

